INSERT INTO words (word, category_id, position, tag, zh, en, example_en, example_zh, synonyms) VALUES
  ('though', 'op', 66, 'OP', '虽然；尽管', 'show contrast with another statement', 'Though the work is hard, we can do it.', '虽然工作很难，我们能完成。', '[{"w":"if","def":"if: 相关的动作或关系词","vs":"与 though 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"if\" / \"though\" 的替换练习"},{"w":"while","def":"while: 可帮助扩展句型的基础词","vs":"与 though 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"while\" / \"though\" 的替换练习"},{"w":"how","def":"how: 同一组 Basic English 操作词","vs":"与 though 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"how\" / \"though\" 的替换练习"}]'),
  ('while', 'op', 67, 'OP', '当……时；而；一段时间', 'during the time that something happens', 'Read while I make the tea.', '我泡茶时你读书。', '[{"w":"though","def":"though: 相关的动作或关系词","vs":"与 while 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"though\" / \"while\" 的替换练习"},{"w":"how","def":"how: 可帮助扩展句型的基础词","vs":"与 while 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"how\" / \"while\" 的替换练习"},{"w":"when","def":"when: 同一组 Basic English 操作词","vs":"与 while 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"when\" / \"while\" 的替换练习"}]'),
  ('how', 'op', 68, 'OP', '怎样；多么；方式', 'ask about manner, condition, or degree', 'How did the glass get broken?', '这个玻璃杯是怎么破的？', '[{"w":"while","def":"while: 相关的动作或关系词","vs":"与 how 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"while\" / \"how\" 的替换练习"},{"w":"when","def":"when: 可帮助扩展句型的基础词","vs":"与 how 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"when\" / \"how\" 的替换练习"},{"w":"where","def":"where: 同一组 Basic English 操作词","vs":"与 how 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"where\" / \"how\" 的替换练习"}]'),
  ('when', 'op', 69, 'OP', '什么时候；当……时', 'ask or say at what time something happens', 'When will the train come?', '火车什么时候来？', '[{"w":"how","def":"how: 相关的动作或关系词","vs":"与 when 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"how\" / \"when\" 的替换练习"},{"w":"where","def":"where: 可帮助扩展句型的基础词","vs":"与 when 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"where\" / \"when\" 的替换练习"},{"w":"why","def":"why: 同一组 Basic English 操作词","vs":"与 when 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"why\" / \"when\" 的替换练习"}]'),
  ('where', 'op', 70, 'OP', '在哪里；到哪里', 'ask or say in what place something is', 'Where did you put the letter?', '你把信放在哪里了？', '[{"w":"when","def":"when: 相关的动作或关系词","vs":"与 where 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"when\" / \"where\" 的替换练习"},{"w":"why","def":"why: 可帮助扩展句型的基础词","vs":"与 where 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"why\" / \"where\" 的替换练习"},{"w":"again","def":"again: 同一组 Basic English 操作词","vs":"与 where 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"again\" / \"where\" 的替换练习"}]');
